import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"网格交易","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/order-types/grid-trading.md","filePath":"zh-CN/stock-trading/order-types/grid-trading.md"}'),t={name:"stock-trading/order-types/grid-trading.md"};function o(h,a,d,n,s,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="网格交易" tabindex="-1">网格交易 <a class="header-anchor" href="#网格交易" aria-label="Permalink to &quot;网格交易&quot;">​</a></h1><p>网格交易是一种基于股价波动的自动化交易策略。投资者事先设定好策略参数（基准价格、触发条件、每笔数量等），系统根据参数自动执行低买高卖，通过反复买卖赚取波段差价。</p><p>注意：网格交易由系统自动下单，不支持需要在下单时手动绑定的卡券（如股票现金卡、平台费抵扣卡等）。通过每日结算同步生效的权益（如终生免佣）可正常适用于网格订单。</p><h2 id="核心参数" tabindex="-1">核心参数 <a class="header-anchor" href="#核心参数" aria-label="Permalink to &quot;核心参数&quot;">​</a></h2><h3 id="基准价格" tabindex="-1">基准价格 <a class="header-anchor" href="#基准价格" aria-label="Permalink to &quot;基准价格&quot;">​</a></h3><p>网格策略的初始计算价格。系统以基准价格为起点，结合触发条件计算上下网格，并实时监控市价是否触及网格。当市价触发网格后，触发价自动成为新的基准价格，用于重新计算后续网格。</p><h3 id="最大价格-最小价格" tabindex="-1">最大价格 / 最小价格 <a class="header-anchor" href="#最大价格-最小价格" aria-label="Permalink to &quot;最大价格 / 最小价格&quot;">​</a></h3><p>整个网格策略运行的有效价格区间，用于风险控制。股价超出该区间时，可选择不做任何委托或直接按最新价清仓。</p><h3 id="触发条件" tabindex="-1">触发条件 <a class="header-anchor" href="#触发条件" aria-label="Permalink to &quot;触发条件&quot;">​</a></h3><p>决定网格大小的参数，可按价差或百分比设置。分别设定上涨和下跌触发网格后的委托价格。</p><p>触发条件要求超过 5 个报价档位且超过基准价的 0.5%，防止收益不足以覆盖交易手续费。</p><p>网格以<strong>实时逐笔成交价</strong>为监控标准，不依赖行情图的显示价格（行情图为按时间加权结果）。美股使用全美行情（NBBO）监控，Basic 行情与全美行情之间可能存在价差，因此行情图显示未达触发条件时网格也可能已执行。</p><p>触发后委托类型：</p><ul><li>市价（市价单）：以当时市场行情决定成交价</li><li>市价（限价单）：以触发时市价为限价，成交价优于或等于限价</li><li>触发价（限价单）：以设定触发价为限价</li></ul><h3 id="每笔委托数量" tabindex="-1">每笔委托数量 <a class="header-anchor" href="#每笔委托数量" aria-label="Permalink to &quot;每笔委托数量&quot;">​</a></h3><p>股价触发网格时的下单数量。</p><h3 id="有效期" tabindex="-1">有效期 <a class="header-anchor" href="#有效期" aria-label="Permalink to &quot;有效期&quot;">​</a></h3><p>支持当日有效、撤销前有效、自定义有效期。</p><h3 id="交易时段" tabindex="-1">交易时段 <a class="header-anchor" href="#交易时段" aria-label="Permalink to &quot;交易时段&quot;">​</a></h3><ul><li>港股：全时段（不含竞价时段）</li><li>美股仅盘中：网格仅在盘中时段执行</li><li>美股盘中 + 盘前盘后：可在盘前、盘中、盘后执行（盘前盘后仅支持限价单，不支持市价市价单）</li></ul><p>注意：网格交易不支持夜盘及港股竞价时段交易。</p><h2 id="进阶参数-跟踪与倍数委托" tabindex="-1">进阶参数：跟踪与倍数委托 <a class="header-anchor" href="#进阶参数-跟踪与倍数委托" aria-label="Permalink to &quot;进阶参数：跟踪与倍数委托&quot;">​</a></h2><h3 id="跟踪回落-跟踪反弹" tabindex="-1">跟踪回落 / 跟踪反弹 <a class="header-anchor" href="#跟踪回落-跟踪反弹" aria-label="Permalink to &quot;跟踪回落 / 跟踪反弹&quot;">​</a></h3><p>开启跟踪回落后，价格上涨到设定值后需回落满足条件才触发卖出。跟踪反弹同理，下跌到最低点后需反弹满足条件才触发买入。</p><h3 id="倍数委托" tabindex="-1">倍数委托 <a class="header-anchor" href="#倍数委托" aria-label="Permalink to &quot;倍数委托&quot;">​</a></h3><p>当股价跳空高开或低开超过一个网格时，按覆盖的网格数量委托对应倍数的每笔委托数量。</p><p>示例：基准价 170，每笔数量 10 股，间隔 1 元，股价跳至 175：</p><ul><li>开启倍数委托：(175 - 170) ÷ 1 × 10 = 50 股卖出</li><li>关闭倍数委托：固定卖出 10 股</li></ul><h3 id="持仓区间" tabindex="-1">持仓区间 <a class="header-anchor" href="#持仓区间" aria-label="Permalink to &quot;持仓区间&quot;">​</a></h3><p>设定最大和最小持仓数，触发网格后若下单会超出持仓区间则不委托。</p><h3 id="支持卖空" tabindex="-1">支持卖空 <a class="header-anchor" href="#支持卖空" aria-label="Permalink to &quot;支持卖空&quot;">​</a></h3><p>开启后持仓为零时可自动做空；关闭后持仓为零不执行卖出。</p><h2 id="基准价格示例" tabindex="-1">基准价格示例 <a class="header-anchor" href="#基准价格示例" aria-label="Permalink to &quot;基准价格示例&quot;">​</a></h2><p>基准价 172，价差触发条件 2 元，每笔委托 2 股：</p><ol><li>172 → 170：触发买入 2 股，新基准价 170</li><li>170 → 168：触发买入 2 股，新基准价 168</li><li>168 → 167：不触发（未达 2 元间隔）</li><li>167 → 170：触发卖出 2 股，新基准价 170</li></ol><h2 id="休眠状态" tabindex="-1">休眠状态 <a class="header-anchor" href="#休眠状态" aria-label="Permalink to &quot;休眠状态&quot;">​</a></h2><p>网格遇到特定条件时自动进入休眠（暂停委托但继续监控市场），条件解除后自动恢复。</p><h3 id="触发休眠的条件" tabindex="-1">触发休眠的条件 <a class="header-anchor" href="#触发休眠的条件" aria-label="Permalink to &quot;触发休眠的条件&quot;">​</a></h3><ul><li>资金或持仓不足：卖出时持仓超限或买入时资金不足</li><li>达到持仓极值：达到设定的最大或最小持仓数</li><li>价格越界：股价超出最高或最低价格区间</li></ul><p>行情满足触发条件但网格未执行时，通常是账户处于休眠状态（资金不足、持仓超限或价格越界），请检查上述条件。</p><h3 id="解除休眠" tabindex="-1">解除休眠 <a class="header-anchor" href="#解除休眠" aria-label="Permalink to &quot;解除休眠&quot;">​</a></h3><ul><li>资金/持仓问题：资金或持仓满足下一次触发条件时自动恢复</li><li>持仓极值：持仓数回落至设定区间时恢复</li><li>价格越界：股价回落至价格区间时恢复</li></ul>',42)])])}const b=e(t,[["render",o]]);export{u as __pageData,b as default};
